// in das even Array
let numbers = [3, 5, 2, 1, 8, 2, 1, 1, 4];
let even = [];

for (let i = 0; i < numbers.length; i++) {
	if (numbers[i] % 2 == 0) {
		even.push(numbers[i]);
	}
}

````

